#include "http_client.h"
#include <WiFi.h>
#include <HTTPClient.h>
void http_client_setup(){Serial.println("[http] OK");}
String http_get(const char*url){
  HTTPClient http;http.begin(url);
  int code=http.GET();String res="";
  if(code>0)res=http.getString();
  http.end();return res;
}
int http_post(const char*url,const char*payload){
  HTTPClient http;http.begin(url);http.addHeader("Content-Type","application/json");
  int code=http.POST(payload);http.end();return code;
}
